 * @param {number} params.D     - コイル中心径 (mm)
 * @param {number} params.Na   - 有効巻数
 * @param {number} params.P    - 荷重 (N)
 * @param {string} params.mat  - 材料キー（SPRING_MATERIALS のキー）
 *
 * @returns {SpringResult}
 *   error    {string|null}   バリデーションエラーメッセージ（null = 正常）
 *   d, D, Na, P, mat         入力値そのまま
 *   G        {number}        横弾性係数 (MPa)
 *   sigmaB   {number}        JIS最小引張強さ (MPa)
 *   C        {number}        ばね指数 (D/d)
 *   K        {number}        Wahl係数
 *   k        {number}        ばね定数 (N/mm)
 *   delta    {number}        たわみ (mm)
 *   tau      {number}        最大せん断応力 (MPa)
 *   ratio    {number}        応力比 τ/σB
 *   Lc       {number}        密着高さ (mm)
 *   Do       {number}        外径 (mm)
 *   Di       {number}        内径 (mm)
 *   Nt       {number}        総巻数
 *   stressOK {boolean}       応力比 ≤ 0.45
 *   cRange   {boolean}       4 ≤ C ≤ 14
 *   isSafe   {boolean}       stressOK && cRange
 *   status   {string}        'OK' | 'NG_STRESS' | 'NG_CRANGE'
 *   warnings {string[]}      警告メッセージ一覧
 */
function springCalc(params) {
  const { d, D, Na, P, mat: matKey } = params;

  const result = {
    error: null,
    d, D, Na, P, mat: matKey,
    G: null, sigmaB: null,
    C: null, K: null, k: null, delta: null, tau: null,
    ratio: null, Lc: null, Do: null, Di: null, Nt: null,
    stressOK: false, cRange: false, isSafe: false,
    status: 'NG_STRESS',
    warnings: [],
  };

  // バリデーション
  const material = SPRING_MATERIALS[matKey];
  if (!material) {
    result.error = `材料データが見つかりません: ${matKey}`;
    return result;
  }
  if (isNaN(d) || d <= 0)  { result.error = '線径 d が無効です'; return result; }
  if (isNaN(D) || D <= 0)  { result.error = '中心径 D が無効です'; return result; }
  if (isNaN(Na) || Na <= 0){ result.error = '有効巻数 Na が無効です'; return result; }
  if (isNaN(P) || P < 0)   { result.error = '荷重 P が無効です'; return result; }

  const G      = material.G;
  const sigmaB = springGetSigmaB(matKey, d);
  const C      = D / d;

  if (C < 2) {
    result.error = `ばね指数 C = ${C.toFixed(2)} < 2（線径が大きすぎます）`;
    return result;
  }

  // JIS B 2704 計算式
  const K     = (4 * C - 1) / (4 * C - 4) + 0.615 / C;
  const k     = G * Math.pow(d, 4) / (8 * Math.pow(D, 3) * Na);
  const delta = k > 0 ? P / k : 0;
  const tau   = 8 * P * D * K / (Math.PI * Math.pow(d, 3));
  const ratio = tau / sigmaB;
  const Lc    = (Na + 2) * d;
  const Do    = D + d;
  const Di    = D - d;
  const Nt    = Na + 2;

  // 安全判定
  const stressOK = ratio <= 0.45;
  const cRange   = C >= 4 && C <= 14;
  const isSafe   = stressOK && cRange;

  let status;
  if (isSafe)           status = 'OK';
  else if (!stressOK)   status = 'NG_STRESS';
  else                  status = 'NG_CRANGE';

  // 警告メッセージ
  const warnings = [];
  if (!stressOK)
    warnings.push(`応力超過: τ/σB = ${ratio.toFixed(4)} > 0.45。線径を太くするかコイル径を大きくしてください。`);
  if (C < 4)
    warnings.push(`ばね指数 C = ${C.toFixed(2)} < 4（推奨範囲）。コイル径を大きくするか線径を細くしてください。`);
  if (C > 14)
    warnings.push(`ばね指数 C = ${C.toFixed(2)} > 14（推奨範囲）。座屈リスクが増加します。`);

  return Object.assign(result, {
    G, sigmaB,
    C, K, k, delta, tau, ratio, Lc, Do, Di, Nt,
    stressOK, cRange, isSafe, status, warnings,
  });
}

