258	// mechsense-core.js を使用（Android assets/ に同梱）
259	const fmt = MechSense.Utils.fmt;
260	let currentMat = 'SW-B';
261	
262	function ge(id){ return document.getElementById(id); }
263	
264	function selectMat(el){
265	  document.querySelectorAll('.mat-pill').forEach(p=>p.classList.remove('active'));
266	  el.classList.add('active');
267	  currentMat = el.dataset.mat;
