277	function calc(){
278	  const d  = parseFloat(ge('sel-d').value);
279	  const Na = parseFloat(ge('sel-na').value);
280	  const D  = parseFloat(ge('inp-D').value);
281	  const P  = parseFloat(ge('inp-P').value);
282	
283	  const r = MechSense.Spring.calc({ d, D, Na, P, mat: currentMat });
284	  if(r.error){ setError(r.error); return; }
285	
286	  const { C, K, k, delta, tau, ratio, Lc, Do, Di, Nt, G, sigmaB, isSafe, stressOK, warnings } = r;
287	
288	  // Badge
289	  const badge = ge('res-badge');
290	  if(isSafe){
291	    badge.className='result-badge badge-ok'; badge.textContent='安全 OK';
292	  } else if(!stressOK){
293	    badge.className='result-badge badge-ng'; badge.textContent='応力超過 NG';
294	  } else {
295	    badge.className='result-badge badge-warn'; badge.textContent='指数注意';
296	  }
297	
