    null,
    ['荷重',        'P',          fmt(P,2),                'N'],
    ['たわみ',      'δ=P/k',      fmt(delta,3),            'mm',    true],
    ['せん断応力',  'τ',          fmt(tau,2),              'MPa',   true],
    ['応力比',      'τ/σB',       fmt(ratio,4),            '—',     true],
    null,
    ['密着高さ',    'Lc=(Na+2)d', fmt(Lc,2),               'mm'],
  ];

