let r = MechSense.Spring.calc({d:2, D:15, Na:5, P:50, mat:'SW-B'});
console.log('Test1 (baseline):', r.status, 'τ/σB='+r.ratio.toFixed(4), 'tauLimit='+r.tauLimit, r.error ? 'ERROR:'+r.error : 'OK');

// テスト2: preset=true
let r2 = MechSense.Spring.calc({d:2, D:15, Na:5, P:50, mat:'SW-B', preset:true});
console.log('Test2 (preset):', r2.status, 'tauLimit='+r2.tauLimit, 'stressOK='+r2.stressOK, r2.error ? 'ERROR' : 'OK');

// テスト3: Lf指定・安全
let r3 = MechSense.Spring.calc({d:2, D:15, Na:5, P:50, mat:'SW-B', Lf:50});
console.log('Test3 (Lf=50mm):', r3.status, 'deltaMax='+r3.deltaMax.toFixed(2), 'P_solid='+r3.P_solid.toFixed(1), 'lambda='+r3.lambda.toFixed(2), 'bottomOut='+r3.bottomOut, r3.error ? 'ERROR' : 'OK');

// テスト4: 底付きケース
let r4 = MechSense.Spring.calc({d:2, D:15, Na:5, P:300, mat:'SW-B', Lf:30});
console.log('Test4 (bottomOut):', r4.status, 'bottomOut='+r4.bottomOut, 'warnings='+r4.warnings.length, r4.error ? 'ERROR:'+r4.error : 'OK');

